{ 
  "@id": (if .["@id"] then .["@id"] else .id end ),
   "@context": (

      if ."@context" | type == "array" then
        ."@context" + [ jsoncontext ]
      else
        ."@context" +  jsoncontext
      end
    ), 
   "asJSON": (. | del(."@context"))
}
